// State tracking - store last seen ticket IDs in workflow static data
const workflowStaticData = $getWorkflowStaticData('global');
if (!workflowStaticData.processedTicketIds) {
  workflowStaticData.processedTicketIds = [];
}
if (!workflowStaticData.lastPollTime) {
  workflowStaticData.lastPollTime = new Date(Date.now() - 60000).toISOString();
}

const lastPoll = workflowStaticData.lastPollTime;
workflowStaticData.lastPollTime = new Date().toISOString();

return [{ json: { lastPollTime: lastPoll, currentTime: workflowStaticData.lastPollTime } }];

// Extract tickets from GLPI response
// GLPI returns array directly or nested under 'data'
const response = $input.first().json;
let tickets = [];

if (Array.isArray(response)) {
  tickets = response;
} else if (response.data && Array.isArray(response.data)) {
  tickets = response.data;
} else if (typeof response === 'object' && !response.error) {
  // Sometimes GLPI returns object with numeric keys
  tickets = Object.values(response).filter(v => typeof v === 'object' && v.id);
}

if (tickets.length === 0) {
  return [{ json: { hasTickets: false, tickets: [] } }];
}

// Filter only new tickets not yet processed
const workflowStaticData = $getWorkflowStaticData('global');
const processedIds = workflowStaticData.processedTicketIds || [];

const newTickets = tickets.filter(t => !processedIds.includes(String(t.id)));

if (newTickets.length === 0) {
  return [{ json: { hasTickets: false, tickets: [] } }];
}

// Mark these as processed
workflowStaticData.processedTicketIds = [
  ...processedIds,
  ...newTickets.map(t => String(t.id))
].slice(-500); // Keep last 500 to avoid memory bloat

// Return each ticket as separate item
return newTickets.map(ticket => ({
  json: {
    hasTickets: true,
    ticketId: ticket.id,
    ticketName: ticket.name || '',
    ticketContent: ticket.content || '',
    ticketStatus: ticket.status,
    ticketPriority: ticket.priority,
    slaId: ticket.slas_id_tto || ticket.slas_id_ttr || null,
    slaName: ticket.slaName || ticket['slas_id_tto.name'] || '',
    dateCreation: ticket.date_creation || ticket.date || '',
    fullTicket: ticket
  }
}));

// Build SLA lookup map from Excel data
// Expected Excel columns: SLA_Name, SLA_Timing (hours), SLA_Meaning (keywords/description)

const excelRows = $input.all();
const slaMap = [];

for (const row of excelRows) {
  const data = row.json;

  // Handle various possible column name formats
  const slaName = data['SLA_Name'] || data['SLA Name'] || data['SLAName'] || data['sla_name'] || '';
  const slaTiming = data['SLA_Timing'] || data['SLA Timing'] || data['SLATiming'] || data['sla_timing'] || data['Hours'] || data['hours'] || '';
  const slaMeaning = data['SLA_Meaning'] || data['SLA Meaning'] || data['SLAMeaning'] || data['sla_meaning'] || data['Meaning'] || data['Keywords'] || '';

  if (!slaName && !slaTiming) continue;

  const timingHours = parseFloat(String(slaTiming).replace(/[^0-9.]/g, '')) || 0;

  slaMap.push({
    slaName: String(slaName).trim(),
    timingHours: timingHours,
    timingLabel: `${timingHours} hour${timingHours !== 1 ? 's' : ''}`,
    slaMeaning: String(slaMeaning).trim(),
    keywords: String(slaMeaning).toLowerCase().split(/[,;|\n]+/).map(k => k.trim()).filter(k => k.length > 2)
  });
}

// Store SLA map in static data for reuse
const workflowStaticData = $getWorkflowStaticData('global');
workflowStaticData.slaMap = slaMap;

console.log(`Loaded ${slaMap.length} SLA rules from Excel`);
return [{ json: { slaMapLoaded: true, slaCount: slaMap.length, slaMap } }];

// Match each ticket against the SLA Excel map
// Input: ticket data from node before IF, SLA map from Excel

const ticket = $('✅ Has New Tickets?').item.json;
const workflowStaticData = $getWorkflowStaticData('global');
const slaMap = workflowStaticData.slaMap || [];

if (slaMap.length === 0) {
  return [{ json: { ...ticket, slaMatched: false, matchReason: 'SLA map not loaded' } }];
}

// Text to analyze - ticket name + content
const ticketText = `${ticket.ticketName} ${ticket.ticketContent} ${ticket.slaName}`.toLowerCase();

let bestMatch = null;
let bestScore = 0;

for (const sla of slaMap) {
  let score = 0;

  // 1. Direct SLA name match from GLPI ticket metadata
  if (ticket.slaName && ticket.slaName.toLowerCase().includes(sla.slaName.toLowerCase())) {
    score += 100;
  }

  // 2. Keyword matching from SLA Meaning column
  for (const keyword of sla.keywords) {
    if (keyword.length > 2 && ticketText.includes(keyword)) {
      score += 10;
    }
  }

  // 3. Direct hour mention in ticket
  const hourPatterns = [
    new RegExp(`${sla.timingHours}\\s*hour`, 'i'),
    new RegExp(`${sla.timingHours}h\\b`, 'i'),
    new RegExp(`sla\\s*${sla.timingHours}`, 'i')
  ];
  for (const pattern of hourPatterns) {
    if (pattern.test(ticketText)) score += 50;
  }

  // 4. SLA name contains hour indicator
  if (sla.slaName && ticketText.includes(sla.slaName.toLowerCase())) {
    score += 80;
  }

  if (score > bestScore) {
    bestScore = score;
    bestMatch = sla;
  }
}

// Fallback: check ticket priority vs SLA timing
// GLPI Priority: 1=Very High, 2=High, 3=Medium, 4=Low, 5=Very Low, 6=Major
if (!bestMatch || bestScore < 10) {
  const priority = parseInt(ticket.ticketPriority) || 3;
  if (priority <= 1) {
    bestMatch = slaMap.find(s => s.timingHours === 1) || slaMap[0];
  } else if (priority <= 2) {
    bestMatch = slaMap.find(s => s.timingHours === 2) || slaMap[1];
  } else if (priority <= 3) {
    bestMatch = slaMap.find(s => s.timingHours === 4) || slaMap[2];
  } else {
    bestMatch = slaMap.find(s => s.timingHours === 6) || slaMap[slaMap.length - 1];
  }
  bestScore = bestMatch ? 5 : 0;
}

if (!bestMatch) {
  return [{ json: { ...ticket, slaMatched: false, matchReason: 'No SLA match found' } }];
}

// Determine if alarm-worthy (1 hour or 2 hour SLA = critical alert)
const isCritical = bestMatch.timingHours <= 2;
const alarmType = bestMatch.timingHours === 1 ? 'ONE_HOUR' : 
                  bestMatch.timingHours === 2 ? 'TWO_HOUR' : 
                  bestMatch.timingHours === 4 ? 'FOUR_HOUR' : 'SIX_HOUR';

return [{
  json: {
    ...ticket,
    slaMatched: true,
    matchScore: bestScore,
    matchedSLA: {
      name: bestMatch.slaName,
      timingHours: bestMatch.timingHours,
      timingLabel: bestMatch.timingLabel,
      meaning: bestMatch.slaMeaning
    },
    isCritical,
    alarmType,
    alarmMessage: `🚨 You have a ${bestMatch.timingLabel} ticket received! Ticket #${ticket.ticketId}: ${ticket.ticketName}`,
    speechText: `Alert! You have a ${bestMatch.timingLabel} SLA ticket received. Ticket number ${ticket.ticketId}. ${ticket.ticketName}. Please respond immediately.`
  }
}];

// Generate alarm HTML page with audio + speech synthesis
// This creates a self-contained alarm page for 1hr and 2hr SLA tickets

const ticket = $input.first().json;
const sla = ticket.matchedSLA;
const isOneHour = sla.timingHours === 1;

const alarmColor = isOneHour ? '#FF0000' : '#FF6600';
const alarmEmoji = isOneHour ? '🔴' : '🟠';
const urgencyText = isOneHour ? 'CRITICAL - 1 HOUR SLA' : 'HIGH PRIORITY - 2 HOUR SLA';

const htmlContent = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>SLA ALARM - Ticket #${ticket.ticketId}</title>
<style>
  body { margin:0; background:#000; font-family:Arial,sans-serif; display:flex; align-items:center; justify-content:center; min-height:100vh; }
  .alarm-box { background:${alarmColor}; color:#fff; padding:40px; border-radius:20px; text-align:center; max-width:600px; animation: pulse 0.5s infinite alternate; box-shadow: 0 0 60px ${alarmColor}; }
  @keyframes pulse { from { transform: scale(1); opacity:1; } to { transform: scale(1.05); opacity:0.85; } }
  .emoji { font-size:80px; }
  .urgency { font-size:28px; font-weight:bold; letter-spacing:3px; margin:10px 0; }
  .ticket-id { font-size:22px; margin:10px 0; }
  .ticket-name { font-size:18px; margin:10px 0; opacity:0.9; }
  .sla-info { background:rgba(0,0,0,0.3); padding:15px; border-radius:10px; margin:15px 0; font-size:16px; }
  .time { font-size:14px; opacity:0.8; margin-top:10px; }
  button { background:#fff; color:${alarmColor}; border:none; padding:15px 30px; font-size:18px; font-weight:bold; border-radius:10px; cursor:pointer; margin-top:15px; }
</style>
</head>
<body>
<div class="alarm-box">
  <div class="emoji">${alarmEmoji} 🔔 ${alarmEmoji}</div>
  <div class="urgency">${urgencyText}</div>
  <div class="ticket-id">Ticket #${ticket.ticketId}</div>
  <div class="ticket-name">${ticket.ticketName || 'New Ticket Received'}</div>
  <div class="sla-info">
    <strong>SLA:</strong> ${sla.name}<br>
    <strong>Response Required Within:</strong> ${sla.timingLabel}<br>
    <strong>SLA Category:</strong> ${sla.meaning}
  </div>
  <div class="time">Received: ${new Date().toLocaleString()}</div>
  <button onclick="stopAlarm()">✅ Acknowledge</button>
</div>

<script>
// Web Audio API alarm beep
const AudioContext = window.AudioContext || window.webkitAudioContext;
let audioCtx;
let alarmInterval;
let isStopped = false;

function beep(frequency, duration, volume) {
  if (isStopped) return;
  audioCtx = audioCtx || new AudioContext();
  const oscillator = audioCtx.createOscillator();
  const gainNode = audioCtx.createGain();
  oscillator.connect(gainNode);
  gainNode.connect(audioCtx.destination);
  oscillator.frequency.value = frequency;
  oscillator.type = 'square';
  gainNode.gain.setValueAtTime(volume, audioCtx.currentTime);
  gainNode.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
  oscillator.start(audioCtx.currentTime);
  oscillator.stop(audioCtx.currentTime + duration);
}

function playAlarm() {
  if (isStopped) return;
  const isOneHour = ${isOneHour};
  if (isOneHour) {
    // Urgent rapid beeping for 1hr SLA
    beep(1200, 0.2, 0.8);
    setTimeout(() => beep(800, 0.2, 0.8), 250);
    setTimeout(() => beep(1200, 0.2, 0.8), 500);
    setTimeout(() => beep(800, 0.2, 0.8), 750);
  } else {
    // Slower alert for 2hr SLA
    beep(900, 0.4, 0.7);
    setTimeout(() => beep(700, 0.4, 0.7), 600);
  }
}

// Speech synthesis
function speakAlert() {
  if (isStopped || !window.speechSynthesis) return;
  const msg = new SpeechSynthesisUtterance('${ticket.speechText.replace(/'/g, "\\'").replace(/"/g, '')}');
  msg.rate = 1.1;
  msg.pitch = 1.2;
  msg.volume = 1.0;
  msg.lang = 'en-US';
  window.speechSynthesis.speak(msg);
}

function stopAlarm() {
  isStopped = true;
  clearInterval(alarmInterval);
  if (window.speechSynthesis) window.speechSynthesis.cancel();
  document.querySelector('.alarm-box').style.animation = 'none';
  document.querySelector('.alarm-box').style.background = '#2d7a2d';
  document.querySelector('.urgency').textContent = '✅ ACKNOWLEDGED';
  document.querySelector('button').textContent = 'Acknowledged - Handle Ticket Now';
  document.querySelector('button').disabled = true;
}

// Start alarm on user interaction (browser autoplay policy)
document.addEventListener('click', function startOnClick() {
  alarmInterval = setInterval(playAlarm, 3000);
  playAlarm();
  speakAlert();
  setTimeout(speakAlert, 8000); // Repeat speech
  document.removeEventListener('click', startOnClick);
}, { once: true });

// Auto-start after 1 second (works in some browsers)
setTimeout(() => {
  try {
    alarmInterval = alarmInterval || setInterval(playAlarm, 3000);
    playAlarm();
    speakAlert();
    setTimeout(speakAlert, 8000);
  } catch(e) {}
}, 1000);
</script>
</body>
</html>`;

return [{
  json: {
    ...ticket,
    alarmHtml: htmlContent,
    alarmGenerated: true
  }
}];

// Log non-critical SLA tickets (4hr, 6hr)
const ticket = $input.first().json;
console.log(`[SLA Monitor] Non-critical ticket #${ticket.ticketId} - SLA: ${ticket.matchedSLA?.timingLabel || 'Unknown'}`);

const workflowStaticData = $getWorkflowStaticData('global');
if (!workflowStaticData.ticketLog) workflowStaticData.ticketLog = [];

workflowStaticData.ticketLog.push({
  ticketId: ticket.ticketId,
  sla: ticket.matchedSLA?.timingLabel,
  name: ticket.ticketName,
  time: new Date().toISOString()
});

// Keep last 200 logs
workflowStaticData.ticketLog = workflowStaticData.ticketLog.slice(-200);

return [{ json: { logged: true, message: `Ticket #${ticket.ticketId} logged - ${ticket.matchedSLA?.timingLabel} SLA` } }];

// No new tickets - silent pass
console.log('[SLA Monitor] Poll complete - no new tickets');
return [{ json: { status: 'no_new_tickets', timestamp: new Date().toISOString() } }];

// Dashboard data aggregator
// Reads ticket log and builds summary for monitoring dashboard
const workflowStaticData = $getWorkflowStaticData('global');
const log = workflowStaticData.ticketLog || [];
const slaMap = workflowStaticData.slaMap || [];

const summary = {
  totalProcessed: log.length,
  lastUpdated: new Date().toISOString(),
  bySlaTier: {},
  last10Tickets: log.slice(-10).reverse()
};

for (const entry of log) {
  const tier = entry.sla || 'Unknown';
  summary.bySlaTier[tier] = (summary.bySlaTier[tier] || 0) + 1;
}

return [{ json: summary }];
